import http from "../01_axios"
import { apiGetBankQR, apiGetFeeTransactionList, apiGetListMemberNeedToPay, 
    apiGetFeeDefinitionForComboBox, apiPostFeeInternal, apiPostFeeExternal, 
    apiPostChangeFeeStatus, apiGetListFeeAssignment, apiGetListAssociationWithDueTracking, 
    apiGetListAssociationComboBox, apiPostConfirmFeeAssignment, apiGetMyFeeAssignment,
    apiDeleteFeeTransaction} from "./urls";

const getFeeTransactionList = params => http.get(apiGetFeeTransactionList, { params });
const getListMemberNeedToPay = params => http.get(apiGetListMemberNeedToPay, {params})
const getFeeDefinitionForComboBox = params => http.get(apiGetFeeDefinitionForComboBox, {params})
const getListFeeAssignment = params => http.get(apiGetListFeeAssignment, {params})
const getListAssociationWithDueTracking = params => http.get(apiGetListAssociationWithDueTracking, {params})
const getListAssociationComboBox = params => http.get(apiGetListAssociationComboBox, {params})
const getMyFeeAssignment = params => http.get(apiGetMyFeeAssignment, {params})
const getBankQR = params => http.get(apiGetBankQR, {params})

const postFeeInternal = body => http.post(apiPostFeeInternal, body)
const postFeeExternal = body => http.post(apiPostFeeExternal, body)
const postConfirmFeeAssignment = body => http.post(apiPostConfirmFeeAssignment, body)
const postChangeFeeStatus = params => http.post(apiPostChangeFeeStatus, {}, { params })
const deleteFeeTransaction = (body) =>http.delete(apiDeleteFeeTransaction, {data: body,});
const FeeManagement = {
    getBankQR,
    getFeeTransactionList,
    getListMemberNeedToPay,
    getFeeDefinitionForComboBox,
    postFeeInternal,
    postFeeExternal,
    postChangeFeeStatus,
    getListFeeAssignment,
    getListAssociationWithDueTracking,
    getListAssociationComboBox,
    postConfirmFeeAssignment,
    getMyFeeAssignment,
    deleteFeeTransaction
}
export default FeeManagement